class Solution:
    def __init__(self, head: Optional[ListNode]):
        self.head = head
    def getRandom(self) -> int:
        node = self.head
        ans, i = 0, 0
        while node:
            i += 1
            if random.randint(1, i) == i:
                ans = node.val
            node = node.next
        return ans

