class Solution {
    ListNode* head;
public:
    Solution(ListNode* h) : head(h) {}
    int getRandom() {
        int ans = 0, i = 0;
        for (ListNode* p = head; p; p = p->next) {
            i++;
            if (rand() % i == 0) ans = p->val;
        }
        return ans;
    }
};

